def classify_critical_point_2d(H):
    """
    H: 2x2 Hessian matrix [[h00,h01],[h10,h11]] at a critical point.
    Returns 'minimum', 'maximum', or 'saddle' based on eigenvalue signs.
    For 2x2: det(H) = h00*h11 - h01*h10, trace(H) = h00 + h11.
    """
    det   = H[0][0]*H[1][1] - H[0][1]*H[1][0]
    trace = H[0][0] + H[1][1]
    if det < 0:
        return ___________
    elif det > 0 and trace > 0:
        return 'minimum'
    elif det > 0 and trace < 0:
        return 'maximum'
    else:
        return 'degenerate'
